      "path": "src/modules/tasks/service.js",
      "content": "const { randomUUID } = require('node:crypto');
const projectsService = require('../projects/service');

function createTask(projectId, title) {
  const project = projectsService.getProjectById(projectId);
  if (!project) return null;
  const task = { id: randomUUID(), title, status: 'todo', comments: [] };
  project.tasks.push(task);
  return task;
}

function getTasksByProjectId(projectId) {
  const project = projectsService.getProjectById(projectId);
  return project ? project.tasks : [];
}

function getTaskById(taskId, projectId) {
  const tasks = getTasksByProjectId(projectId);
  return tasks.find(task => task.id === taskId);
}

function updateTaskStatus(taskId, projectId, status) {
  if (!['todo', 'done'].includes(status)) return null;
  const task = getTaskById(taskId, projectId);
  if (!task) return null;
  task.status = status;
  return task;
}

module.exports = {
  createTask,
  getTasksByProjectId,
  getTaskById,
  updateTaskStatus,
};
